script:
frappe.ui.form.on("Hostel Room", {
    refresh(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button("Occupancy History", function () {
                frappe.set_route("List", "Hostel Admission", {
                    hostel_room: frm.doc.name
                });
            }, "View");
        }
    }
});
